{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "bash -c 'INPUT=$(cat); CMD=$(echo \"$INPUT\" | jq -r \".tool_input.command\"); if echo \"$CMD\" | grep -qE \"rm -rf|rm -f /|: > /|truncate -s 0\"; then echo \"Blocked: destructive command\" >&2; exit 2; fi'"
          }
        ]
      }
    ]
  }
}

{
  "mcpServers": {
    "my-local-tool": {
      "type": "stdio",
      "command": "node",
      "args": ["./mcp-server.js"],
      "env": {
        "LOG_LEVEL": "info"
      }
    }
  }
}

{
  "mcpServers": {
    "my-server": {
      "command": "npx",
      "args": ["-y", "@my-org/mcp-server", "--config", "/path/to/config"],
      "env": {
        "API_KEY": "your-key-here"
      }
    }
  }
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({
  name: "my-server",
  version: "1.0.0",
});

server.registerTool(
  "my_tool",
  {
    description: "Execute a query.",
    inputSchema: { query: z.string() },
  },
  async ({ query }) => ({
    content: [{ type: "text", text: `Result for: ${query}` }],
  })
);

const transport = new StdioServerTransport();
await server.connect(transport);
